// Chaos Swarm — CLI entry (Gnosis core). Thin wrapper around `gnosis_chaos`.

use gnosis_chaos::{
    free_manifold_string, tick_parallel_manifold, weyl_next, ChaosConfig, ChaosEngine,
    STATIC_SERVER,
};

fn main() {
    let args: Vec<String> = std::env::args().collect();

    if let Some(index) = args.iter().position(|r| r == "--ffi-json") {
        if let Some(json_input) = args.get(index + 1) {
            let input_ptr = std::ffi::CString::new(json_input.clone())
                .unwrap()
                .into_raw();
            let output_ptr = tick_parallel_manifold(input_ptr);

            if !output_ptr.is_null() {
                let c_str = unsafe { std::ffi::CStr::from_ptr(output_ptr) };
                println!("{}", c_str.to_str().unwrap());
                free_manifold_string(output_ptr);
            }
            return;
        }
    }

    let seed = 42;
    let rounds = args.get(1).and_then(|s| s.parse().ok()).unwrap_or(100_000);

    let mut config = ChaosConfig::default();
    if let Some(rate) = args.get(2).and_then(|s| s.parse().ok()) {
        config.target_survival_rate = rate;
    }

    println!("Booting Native Chaos Swarm Engine (gnosis-chaos)...");
    println!(
        "Target Survival Rate: {:.2}%",
        config.target_survival_rate * 100.0
    );

    let topology = &STATIC_SERVER;
    if args.contains(&"--mutate".to_string()) {
        let mut seed_n = seed + 100;
        let _ = weyl_next(&mut seed_n);
        println!("GENETIC: Mutation pass would go here (Refactoring in progress).");
    }

    let mut engine = ChaosEngine::new(seed, config, topology);

    let start = std::time::Instant::now();
    engine.tick_monte_carlo(rounds);
    let elapsed = start.elapsed();

    let active_survivors = engine.agents.iter().filter(|a| a.energy > 0).count();

    println!("\nSimulation Complete. Reaping Metrics:");
    println!("------------------------------------");
    println!("Duration: {:?}", elapsed);
    println!(
        "Throughput (Sinks Reached): {}",
        engine.metrics.total_throughput
    );

    let survival_rate =
        (active_survivors as f64 / engine.metrics.total_agent_population as f64) * 100.0;
    println!(
        "Active Survivors at T_Final: {} ({:.2}%)",
        active_survivors, survival_rate
    );
    println!("Final Clinamen Pressure: {}", engine.clinamen_pressure);

    let human_win_time_seconds = 300.0;
    let total_wins = engine.metrics.total_throughput as f64;
    let total_hours = (total_wins * human_win_time_seconds) / 3600.0;
    println!(
        "Estimated Human Playing Time: {:.2} Years",
        total_hours / 24.0 / 365.25
    );
    println!("------------------------------------");
}
